import Case from "../models/Case.js";
import Evidence from "../models/Evidence.js";
import { generateCaseAnalysisSummary } from "../services/openaiService.js";

/**
 * Create a new case
 * POST /api/cases
 */
const createCase = async (req, res) => {
  try {
    const {
      title,
      description,
      jurisdiction,
      assignedOfficer,
      caseType,
      status,
      crime,
      victim,
      witness,
      suspect,
      tags,
      metadata,
    } = req.body;

    // NOTE: caseNumber is intentionally NOT extracted from req.body
    // It will be auto-generated by the schema pre-validate hook

    // Validation
    if (!title || title.trim() === "") {
      return res.status(400).json({
        success: false,
        message: "Case title is required",
      });
    }

    if (!jurisdiction || jurisdiction.trim() === "") {
      return res.status(400).json({
        success: false,
        message: "Jurisdiction is required",
      });
    }

    if (!description || description.trim() === "") {
      return res.status(400).json({
        success: false,
        message: "Description is required",
      });
    }

    const validCaseTypes = ["criminal", "civil", "corporate", "cyber", "other"];
    const normalizedCaseType = validCaseTypes.includes(caseType)
      ? caseType
      : "other";
    const validStatuses = [
      "open",
      "in-progress",
      "closed",
      "archived",
      "suspended",
    ];
    const normalizedStatus = validStatuses.includes(status) ? status : "open";

    // Create case (caseNumber will be auto-generated)
    const newCase = await Case.create({
      title: title.trim(),
      description: (description || "").trim(),
      jurisdiction: jurisdiction.trim(),
      caseType: normalizedCaseType,
      status: normalizedStatus,
      assignedOfficer: assignedOfficer || null,
      crime: crime || {},
      victim: victim || {},
      witness: witness || {},
      suspect: suspect || {},
      evidence: [],
      tags: tags || [],
      metadata: metadata || {},
      // DO NOT include caseNumber here - let the schema generate it
    });

    console.log("✅ Case created:", newCase.caseNumber);

    // Add initial timeline entry
    newCase.timeline.push({
      event: "Case Created",
      date: new Date(),
      description: `Case created by ${req.user.username || req.user.name || "user"}`,
      recordedBy: req.user.id,
    });

    // Generate AI analysis summary using OpenAI
    console.log("🔄 Generating case analysis summary with OpenAI...");
    const analysisSummary = await generateCaseAnalysisSummary(
      newCase.toObject(),
    );
    if (analysisSummary) {
      newCase.caseAnalysisSummary = {
        caseSummary: analysisSummary,
        evidenceSummary: null,
        lastUpdated: new Date(),
      };
      console.log("✅ Case analysis summary generated and stored");
    } else {
      console.log(
        "⚠️ Failed to generate case analysis summary, continuing without it",
      );
    }

    await newCase.save();

    // Populate user references before sending response
    await newCase.populate("assignedOfficer", "username email role");

    // NOTE: We intentionally do NOT return the caseAnalysisSummary in the response
    // It's stored in the database for later use (comparisons, reports, etc.)
    const caseResponse = newCase.toObject();
    delete caseResponse.caseAnalysisSummary;

    res.status(201).json({
      success: true,
      message: "Case created successfully",
      data: caseResponse,
    });
  } catch (error) {
    console.error("❌ Create case error:", error);
    res.status(500).json({
      success: false,
      message: "Error creating case",
      error: error.message,
    });
  }
};

/**
 * Get all cases
 * GET /api/cases
 * Query params: status, caseType, search
 */
const getAllCases = async (req, res) => {
  try {
    const { status, caseType, search, limit = 50, page = 1 } = req.query;

    // Build filter
    const filter = {};

    if (status) {
      filter.status = status;
    }

    if (caseType) {
      filter.caseType = caseType;
    }

    // Search in title and description
    if (search) {
      filter.$or = [
        { title: { $regex: search, $options: "i" } },
        { description: { $regex: search, $options: "i" } },
        { caseNumber: { $regex: search, $options: "i" } },
      ];
    }

    // Calculate pagination
    const skip = (parseInt(page) - 1) * parseInt(limit);

    // Get total count for pagination
    const totalCases = await Case.countDocuments(filter);

    // Get cases with pagination
    const cases = await Case.find(filter)
      .populate("assignedOfficer", "username email role")
      .populate("evidence", "evidenceId fileName ipfsHash status")
      .sort({ createdAt: -1 })
      .limit(parseInt(limit))
      .skip(skip);

    res.status(200).json({
      success: true,
      count: cases.length,
      total: totalCases,
      page: parseInt(page),
      totalPages: Math.ceil(totalCases / parseInt(limit)),
      data: cases,
    });
  } catch (error) {
    console.error("❌ Get all cases error:", error);
    res.status(500).json({
      success: false,
      message: "Error retrieving cases",
      error: error.message,
    });
  }
};

/**
 * Get single case by ID
 * GET /api/cases/:id
 */
const getCaseById = async (req, res) => {
  try {
    const caseData = await Case.findById(req.params.id)
      .populate("assignedOfficer", "username email role walletAddress")
      .populate({
        path: "evidence",
        select:
          "evidenceId fileName fileType fileSize ipfsHash fileHash status createdAt",
        options: { sort: { createdAt: -1 } },
      })
      .populate("timeline.recordedBy", "username");

    if (!caseData) {
      return res.status(404).json({
        success: false,
        message: "Case not found",
      });
    }

    res.status(200).json({
      success: true,
      data: caseData,
    });
  } catch (error) {
    console.error("❌ Get case error:", error);

    // Handle invalid ObjectId
    if (error.kind === "ObjectId") {
      return res.status(404).json({
        success: false,
        message: "Case not found - invalid ID format",
      });
    }

    res.status(500).json({
      success: false,
      message: "Error retrieving case",
      error: error.message,
    });
  }
};

/**
 * Find similar cases
 * GET /api/cases/analyze/similar/:id
 */
const findSimilarCases = async (req, res) => {
  try {
    const currentCase = await Case.findById(req.params.id);

    if (!currentCase) {
      return res.status(404).json({
        success: false,
        message: "Case not found",
      });
    }

    // Build similarity criteria
    const similarityFilters = [];

    // 1. Same case type
    similarityFilters.push({
      caseType: currentCase.caseType,
      _id: { $ne: currentCase._id },
    });

    // 2. Matching tags
    if (currentCase.tags && currentCase.tags.length > 0) {
      similarityFilters.push({
        tags: { $in: currentCase.tags },
        _id: { $ne: currentCase._id },
      });
    }

    // 3. Same location
    if (currentCase.metadata?.location) {
      similarityFilters.push({
        "metadata.location": currentCase.metadata.location,
        _id: { $ne: currentCase._id },
      });
    }

    // 4. Similar incident timeframe (within 30 days)
    if (currentCase.metadata?.incidentDate) {
      const incidentDate = new Date(currentCase.metadata.incidentDate);
      const dateRange = 30 * 24 * 60 * 60 * 1000;

      similarityFilters.push({
        "metadata.incidentDate": {
          $gte: new Date(incidentDate.getTime() - dateRange),
          $lte: new Date(incidentDate.getTime() + dateRange),
        },
        _id: { $ne: currentCase._id },
      });
    }

    // Find similar cases
    const similarCases = await Case.find({
      $or: similarityFilters,
    })
      .populate("assignedOfficer", "username email")
      .populate("evidence", "evidenceId fileName")
      .select("caseNumber title caseType status metadata tags createdAt")
      .sort({ createdAt: -1 })
      .limit(10);

    // Calculate similarity scores
    const casesWithScores = similarCases.map((similarCase) => {
      let score = 0;
      const reasons = [];

      if (similarCase.caseType === currentCase.caseType) {
        score += 3;
        reasons.push("Same case type");
      }

      if (currentCase.tags && similarCase.tags) {
        const matchingTags = currentCase.tags.filter((tag) =>
          similarCase.tags.includes(tag),
        );
        if (matchingTags.length > 0) {
          score += matchingTags.length * 2;
          reasons.push(`${matchingTags.length} matching tag(s)`);
        }
      }

      if (
        currentCase.metadata?.location &&
        similarCase.metadata?.location === currentCase.metadata?.location
      ) {
        score += 4;
        reasons.push("Same location");
      }

      if (
        currentCase.metadata?.incidentDate &&
        similarCase.metadata?.incidentDate
      ) {
        const timeDiff = Math.abs(
          new Date(currentCase.metadata.incidentDate) -
            new Date(similarCase.metadata.incidentDate),
        );
        const daysDiff = timeDiff / (1000 * 60 * 60 * 24);

        if (daysDiff <= 30) {
          score += 2;
          reasons.push(`Incident within ${Math.round(daysDiff)} days`);
        }
      }

      return {
        ...similarCase.toObject(),
        similarityScore: score,
        similarityReasons: reasons,
      };
    });

    casesWithScores.sort((a, b) => b.similarityScore - a.similarityScore);
    const relevantCases = casesWithScores.filter((c) => c.similarityScore >= 2);

    res.status(200).json({
      success: true,
      count: relevantCases.length,
      currentCase: {
        id: currentCase._id,
        caseNumber: currentCase.caseNumber,
        title: currentCase.title,
      },
      data: relevantCases,
    });
  } catch (error) {
    console.error("❌ Find similar cases error:", error);

    if (error.kind === "ObjectId") {
      return res.status(404).json({
        success: false,
        message: "Case not found - invalid ID format",
      });
    }

    res.status(500).json({
      success: false,
      message: "Error finding similar cases",
      error: error.message,
    });
  }
};

/**
 * Update case
 * PUT /api/cases/:id
 */
const updateCase = async (req, res) => {
  try {
    const {
      title,
      description,
      jurisdiction,
      status,
      assignedOfficer,
      caseType,
      crime,
      victim,
      witness,
      suspect,
      tags,
      metadata,
    } = req.body;

    // NOTE: caseNumber is NOT accepted for updates - it's immutable

    const caseData = await Case.findById(req.params.id);

    if (!caseData) {
      return res.status(404).json({
        success: false,
        message: "Case not found",
      });
    }

    // Update fields if provided
    if (title) caseData.title = title.trim();
    if (description) caseData.description = description.trim();
    if (jurisdiction) caseData.jurisdiction = jurisdiction.trim();
    if (status) caseData.status = status;
    if (assignedOfficer) caseData.assignedOfficer = assignedOfficer;
    if (caseType) caseData.caseType = caseType;
    if (crime) caseData.crime = { ...caseData.crime, ...crime };
    if (victim) caseData.victim = { ...caseData.victim, ...victim };
    if (witness) caseData.witness = { ...caseData.witness, ...witness };
    if (suspect) caseData.suspect = { ...caseData.suspect, ...suspect };
    if (tags) caseData.tags = tags;
    if (metadata) caseData.metadata = { ...caseData.metadata, ...metadata };

    // Add timeline entry
    caseData.timeline.push({
      event: "Case Updated",
      date: new Date(),
      description: `Case updated by ${req.user.username || req.user.name || "user"}`,
      recordedBy: req.user.id,
    });

    await caseData.save();

    await caseData.populate("assignedOfficer", "username email");

    res.status(200).json({
      success: true,
      message: "Case updated successfully",
      data: caseData,
    });
  } catch (error) {
    console.error("❌ Update case error:", error);
    res.status(500).json({
      success: false,
      message: "Error updating case",
      error: error.message,
    });
  }
};

/**
 * Close case
 * PUT /api/cases/:id/close
 */
const closeCase = async (req, res) => {
  try {
    const { findings } = req.body;

    const caseData = await Case.findById(req.params.id);

    if (!caseData) {
      return res.status(404).json({
        success: false,
        message: "Case not found",
      });
    }

    if (caseData.status === "closed") {
      return res.status(400).json({
        success: false,
        message: "Case is already closed",
      });
    }

    caseData.status = "closed";
    caseData.metadata = caseData.metadata || {};
    caseData.metadata.closedDate = new Date();

    caseData.timeline.push({
      event: "Case Closed",
      date: new Date(),
      description:
        findings ||
        `Case closed by ${req.user.username || req.user.name || "user"}`,
      recordedBy: req.user.id,
    });

    await caseData.save();

    res.status(200).json({
      success: true,
      message: "Case closed successfully",
      data: caseData,
    });
  } catch (error) {
    console.error("❌ Close case error:", error);
    res.status(500).json({
      success: false,
      message: "Error closing case",
      error: error.message,
    });
  }
};

/**
 * Add timeline entry
 * POST /api/cases/:id/timeline
 */
const addTimelineEntry = async (req, res) => {
  try {
    const { event, description } = req.body;

    if (!event || !description) {
      return res.status(400).json({
        success: false,
        message: "Event and description are required",
      });
    }

    const caseData = await Case.findById(req.params.id);

    if (!caseData) {
      return res.status(404).json({
        success: false,
        message: "Case not found",
      });
    }

    caseData.timeline.push({
      event: event.trim(),
      date: new Date(),
      description: description.trim(),
      recordedBy: req.user.id,
    });

    await caseData.save();

    res.status(200).json({
      success: true,
      message: "Timeline entry added",
      data: caseData.timeline[caseData.timeline.length - 1],
    });
  } catch (error) {
    console.error("❌ Add timeline entry error:", error);
    res.status(500).json({
      success: false,
      message: "Error adding timeline entry",
      error: error.message,
    });
  }
};

/**
 * Link evidence to case
 * POST /api/cases/:id/evidence/:evidenceId
 */
const linkEvidence = async (req, res) => {
  try {
    const { id: caseId, evidenceId } = req.params;

    const caseData = await Case.findById(caseId);

    if (!caseData) {
      return res.status(404).json({
        success: false,
        message: "Case not found",
      });
    }

    const evidence = await Evidence.findById(evidenceId);

    if (!evidence) {
      return res.status(404).json({
        success: false,
        message: "Evidence not found",
      });
    }

    if (caseData.evidence.some((id) => id.toString() === evidenceId)) {
      return res.status(400).json({
        success: false,
        message: "Evidence already linked to this case",
      });
    }

    caseData.evidence.push(evidenceId);
    evidence.caseId = caseData._id;
    await evidence.save();

    caseData.timeline.push({
      event: "Evidence Linked",
      date: new Date(),
      description: `Evidence ${evidence.evidenceId} linked to case`,
      recordedBy: req.user.id,
    });

    await caseData.save();

    res.status(200).json({
      success: true,
      message: "Evidence linked successfully",
      data: {
        caseNumber: caseData.caseNumber,
        evidenceId: evidence.evidenceId,
      },
    });
  } catch (error) {
    console.error("❌ Link evidence error:", error);
    res.status(500).json({
      success: false,
      message: "Error linking evidence",
      error: error.message,
    });
  }
};

