/**
 * Get evidence upload trend (weekly data for graph)
 * GET /api/cases/dashboard/evidence-trend
 */
const getEvidenceUploadTrend = async (req, res) => {
  try {
    // Get last 4 weeks of data
    const weeks = [];
    const today = new Date();

    // Create array of last 4 weeks' start dates (Monday)
    for (let i = 3; i >= 0; i--) {
      const d = new Date(today);
      d.setDate(d.getDate() - d.getDay() + 1 - i * 7); // Get Monday of each week
      weeks.push({
        startDate: new Date(d),
        weekNumber: i,
      });
    }

    // Get evidence counts for each week
    const trendData = [];
    const weekLabels = ["Week 1", "Week 2", "Week 3", "Week 4"];

    for (let i = 0; i < weeks.length; i++) {
      const currentWeekStart = weeks[i].startDate;
      const nextWeekStart = new Date(currentWeekStart);
      nextWeekStart.setDate(nextWeekStart.getDate() + 7);

      const count = await Evidence.countDocuments({
        createdAt: {
          $gte: currentWeekStart,
          $lt: nextWeekStart,
        },
      });

      trendData.push({
        month: weekLabels[i],
        count: count,
      });
    }

    res.status(200).json({
      success: true,
      data: trendData,
    });
  } catch (error) {
    console.error("❌ Get evidence trend error:", error);
    res.status(500).json({
      success: false,
      message: "Error retrieving evidence trend",
      error: error.message,
    });
  }
};

/**
 * Get recent activity (latest evidence uploads and case updates)
 * GET /api/cases/dashboard/recent-activity
 */
const getRecentActivity = async (req, res) => {
  try {
    const activities = [];

    // Get recent evidence uploads (last 10)
    const recentEvidence = await Evidence.find()
      .populate("uploader", "username")
      .sort({ createdAt: -1 })
      .limit(10);

    // Get recent case updates (last 10)
    const recentCases = await Case.find()
      .select("_id caseNumber title status createdAt updatedAt")
      .sort({ updatedAt: -1 })
      .limit(10);

    // Format evidence uploads as activities
    recentEvidence.forEach((evidence) => {
      const timeAgo = getTimeAgo(evidence.createdAt);
      activities.push({
        id: evidence.evidenceId,
        action: "Evidence Uploaded",
        user: evidence.uploader?.username || "Unknown User",
        time: timeAgo,
        timestamp: evidence.createdAt,
        type: "evidence",
      });
    });

    // Format case updates as activities
    recentCases.forEach((caseItem) => {
      const timeAgo = getTimeAgo(caseItem.updatedAt);
      activities.push({
        id: caseItem.caseNumber,
        action: `Case ${caseItem.status === "closed" ? "Closed" : "Updated"}`,
        user: "System",
        time: timeAgo,
        timestamp: caseItem.updatedAt,
        type: "case",
      });
    });

    // Sort by timestamp (most recent first)
    activities.sort((a, b) => b.timestamp - a.timestamp);

    // Return top 6 most recent activities
    const recentActivities = activities.slice(0, 6);

    res.status(200).json({
      success: true,
      data: recentActivities,
    });
  } catch (error) {
    console.error("❌ Get recent activity error:", error);
    res.status(500).json({
      success: false,
      message: "Error retrieving recent activity",
      error: error.message,
    });
  }
};
/**
 * Helper function to format time difference
 */
function getTimeAgo(date) {
  const now = new Date();
  const seconds = Math.floor((now - date) / 1000);

  if (seconds < 60) return "just now";
  if (seconds < 3600) return `${Math.floor(seconds / 60)} minutes ago`;
  if (seconds < 86400) return `${Math.floor(seconds / 3600)} hours ago`;
  if (seconds < 604800) return `${Math.floor(seconds / 86400)} days ago`;

  return date.toLocaleDateString();
}

export {
  createCase,
  getAllCases,
  getCaseById,
  findSimilarCases,
  updateCase,
  closeCase,
  addTimelineEntry,
  linkEvidence,
  getCaseStats,
  getEvidenceUploadTrend,
  getRecentActivity,
};
